class Solution:
    def kthSmallestPrimeFraction(self, arr, k):
        fracs = []
        n = len(arr)
        for j in range(n):
            for i in range(j):
                fracs.append((arr[i] / arr[j], arr[i], arr[j]))
        fracs.sort()
        return [fracs[k - 1][1], fracs[k - 1][2]]

