class Solution:
    def kthSmallestPrimeFraction(self, arr, k):
        n = len(arr)
        lo, hi = 0.0, 1.0
        while True:
            mid = (lo + hi) / 2
            count = 0
            best_p, best_q = 0, 1
            j = 1
            for i in range(n):
                while j < n and arr[i] > mid * arr[j]:
                    j += 1
                count += n - j
                if j < n and best_p * arr[j] < arr[i] * best_q:
                    best_p, best_q = arr[i], arr[j]
            if count == k:
                return [best_p, best_q]
            elif count < k:
                lo = mid
            else:
                hi = mid

