var kthSmallestPrimeFraction = function(arr, k) {
    const n = arr.length;
    let lo = 0.0, hi = 1.0;
    while (true) {
        const mid = (lo + hi) / 2;
        let count = 0;
        let bestP = 0, bestQ = 1;
        let j = 1;
        for (let i = 0; i < n; i++) {
            while (j < n && arr[i] > mid * arr[j]) j++;
            count += n - j;
            if (j < n && bestP * arr[j] < arr[i] * bestQ) {
                bestP = arr[i];
                bestQ = arr[j];
            }
        }
        if (count === k) return [bestP, bestQ];
        else if (count < k) lo = mid;
        else hi = mid;
    }
};
